    public static class AzureFunction
    {
        [FunctionName("AzureFunction")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequest req)
        {
            string queryString = req.Query["query"];
            string tableName = req.Query["table"];
            string filterParam1 = req.Query["filter_param1"];
            string filterParam2 = req.Query["filter_param2"];

            // Construct dynamic SQL query using query string parameters
            string sqlQuery = $"SELECT * FROM {tableName} WHERE {filterParam1} > 0";

