            // Use SqlConnection to execute the query
            using (SqlConnection connection = new SqlConnection("Server=tcp:<server_name>.database.windows.net,1433;Database=<db_name>;User ID=<username>@<server_name>;Password=<password>;Trusted_Connection=False;Encrypt=True;"))
            {
                connection.Open();
